const patientMergeResultSchemaResponseTransformer = (data: any) => {
    data.targetPatient.createdAt = new Date(data.targetPatient.createdAt);
    data.targetPatient.updatedAt = new Date(data.targetPatient.updatedAt);
    if (data.targetPatient.identifiers) {
        data.targetPatient.identifiers = data.targetPatient.identifiers.map((item: any) => healthcareCoreIdentifierSchemaResponseTransformer(item));
    }
    if (data.targetPatient.extensions) {
        data.targetPatient.extensions = data.targetPatient.extensions.map((item: any) => healthcareCoreResourceExtensionSchemaResponseTransformer(item));
    }
    data.targetPatient.name = data.targetPatient.name.map((item: any) => healthcareCoreHumanNameSchemaResponseTransformer(item));
    data.targetPatient.birthDate = new Date(data.targetPatient.birthDate);
    if (data.targetPatient.deceasedDateTime) {
        data.targetPatient.deceasedDateTime = new Date(data.targetPatient.deceasedDateTime);
    }
    if (data.targetPatient.telecom) {
        data.targetPatient.telecom = data.targetPatient.telecom.map((item: any) => healthcareCoreContactPointSchemaResponseTransformer(item));
    }
    if (data.targetPatient.photo) {
        data.targetPatient.photo = data.targetPatient.photo.map((item: any) => healthcareCoreAttachmentSchemaResponseTransformer(item));
    }
    if (data.targetPatient.emergencyContact) {
        data.targetPatient.emergencyContact = data.targetPatient.emergencyContact.map((item: any) => emergencyContactSchemaResponseTransformer(item));
    }
    data.recordsUpdated = BigInt(data.recordsUpdated.toString());
    return data;
};

